   256			ApplicationContext context = getBuilder().getSharedObject(ApplicationContext.class);
   257			if (context != null && context.getBeanNamesForType(AuthenticationEventPublisher.class).length > 0) {
   258				return context.getBean(AuthenticationEventPublisher.class);
   259			}
   260			return new DefaultAuthenticationEventPublisher();
